   {"type":"word_form","base":"ISSUE","sentence":"The ___ of a certificate is now automated.","a":"issuance","alts":["issuance"],"explain":"Verb → noun: -ance."},
   {"type":"word_form","base":"REVOKE","sentence":"___ must happen before expiry.","a":"Revocation","alts":["Revocation"],"explain":"-ation noun."},
