   {"type":"word_form","base":"COMPROMISE","sentence":"Key ___ triggers revocation.","a":"compromise","alts":["compromise"],"explain":"Verb / noun same."},
   {"type":"word_form","base":"AUDIT","sentence":"Logs must be publicly ___ .","a":"auditable","alts":["auditable"],"explain":"-able adjective."},
