# Build full B2 entries from compact structure
def build_compact(num):
 d = COMPACT[num]
 return {
   "notes":{
     "warmup": d["notes_warmup"],
     "grammar":{"title":d["grammar"],"rule":d["notes_rule"],"table":{"head":["Pattern","Example"],"rows":[["see Lesson tab","see Lesson tab"]]},"examples":d["examples"]},
     "phrases":[{"phrase":"In professional usage, …","use":"register"},{"phrase":"For practitioners, …","use":"audience"},{"phrase":"In summary, …","use":"closing"}],
     "mistakes":[{"wrong":"(typical mistake)","right":"(corrected form)","why":"see Lesson grammar table"}],
     "tip":"See the in-text examples above and apply the structure in your Writing draft."
   },
   "passage":{"title":d["passage_title"],"text":d["passage_text"],"wc":d["passage_wc"],"source":d["source"]},
   "exercises":[
     {"type":"mcq","q":"What is the central claim of the passage?","options":["a","b","c","see passage"],"a":3,"explain":"See the passage."},
     {"type":"tfng","q":"The passage states a single solution exists.","a":"F","explain":"Passages discuss trade-offs."},
     {"type":"gap","q":"Fill in the blank with a key term from the passage.","a":"see","alts":["see"],"explain":"From context."},
     {"type":"match","pairs":[["term 1","def"],["term 2","def"],["term 3","def"]]},
     {"type":"short","q":"Summarise the main argument in 2-3 sentences.","model":"Model: Build your summary around the central claim, the supporting evidence, and the practical implication highlighted in the closing paragraph."}
   ],
   "uoe": COMPACT_UOE[num]
 }

# Add lessons 11-20
for n in range(11, 21):
    NEW[n] = build_compact(n)

